function projectDocument(document, fieldPaths) {
    const project = (doc, path) => {
        const pathParts = path.split('.');
        let current = doc;
        for (let part of pathParts) {
            if (current[part] !== undefined) {
                current = current[part];
            } else {
                break;
            }
        }
        return current;
    }
    const projectedDocument = {};
    for (let fieldPath of fieldPaths) {
        projectedDocument[fieldPath] = project(document, fieldPath);
    }
    return JSON.stringify(projectedDocument);
}

