import json
class Solution:
    def projectDocument(self, document, fieldPaths):
        def project(doc, path):
            path_parts = path.split('.')
            current = doc
            for part in path_parts:
                if part in current:
                    current = current[part]
                else:
                    break
            return current
        projected_document = {}
        for field_path in fieldPaths:
            projected_document[field_path] = project(document, field_path)
        return json.dumps(projected_document)
